        &#125;else if(val &lt;&#x3D; min.peek()) &#123; &#x2F;&#x2F;注意与最小值相等也要再压一次，弹出的时候才能持平
            min.push(val);
        &#125;
        value.push(val);
    &#125;

    public int pop() &#123;
        if(value.peek().equals(min.peek())) &#123;
            min.pop();
        &#125;

        return value.pop();
    &#125;

    public int top() &#123;
        return value.peek();
    &#125;

    public int getMin() &#123;
        return min.peek();
