        p&#123;
          color:green;
        &#125;

        .class1&#123;
          color:blue;
        &#125;
    &lt;&#x2F;style&gt;

&lt;&#x2F;head&gt;
&lt;body&gt;
  &lt;div id&#x3D;&quot;div1&quot;&gt;张杰&lt;&#x2F;div&gt;
  &lt;p&gt;张杰2&lt;&#x2F;p&gt;
  &lt;p class&#x3D;&quot;class1&quot;&gt;zhangjie&lt;&#x2F;p&gt;
