class Solution &#123;
    public ListNode removeDuplicateNodes(ListNode head) &#123;
         if (head &#x3D;&#x3D; null) &#123;
            return head;
        &#125;
        Set&lt;Integer&gt; occurred &#x3D; new HashSet&lt;Integer&gt;();
        occurred.add(head.val);
